import"./main.min.js";import"./programs-course.min2.js";import"./index.min2.js";import"./watcher.min.js";import"./common.min.js";document.addEventListener("DOMContentLoaded",()=>{const r=document.querySelectorAll(".programs-course__control"),o=document.querySelectorAll(".programs-course__cards .programs-course__card");r.forEach(s=>{s.addEventListener("click",()=>{const t=s.dataset.filter;r.forEach(e=>e.classList.remove("active")),s.classList.add("active"),o.forEach(e=>{if(t==="all")e.style.display="grid";else{const c=t.replace(".","");e.classList.contains(c)?e.style.display="grid":e.style.display="none"}})})})});
